styles:
ytd-watch-flexy:not([theater]):not([fullscreen]):not(
    [show-engagement-panel-scrim__]
  )
  #secondary-inner { position: fixed;
  overflow-x: hidden;
  overflow-y: auto;
  height: calc(
    100vh - var(--ytd-watch-flexy-masthead-height) - var(--ytd-margin-6x) * 2
  );
  max-width: var(--ytd-watch-flexy-sidebar-width);
  scrollbar-width: thin !important; }

ytd-watch-flexy {
  --ytd-watch-flexy-comments-panel-max-height: calc(
    100vh - var(--ytd-watch-flexy-masthead-height) - var(--ytd-margin-6x) * 2
  ) !important;
  --ytd-watch-flexy-panel-max-height: calc(
    100vh - var(--ytd-watch-flexy-masthead-height) - var(--ytd-margin-6x) * 2
  ) !important;
  --ytd-watch-flexy-chat-max-height: calc(
    100vh - var(--ytd-watch-flexy-masthead-height) - var(--ytd-margin-6x) * 2
  ) !important;
}

stylesDesktop:
#summarizeButtonContainer button {
        display: flex !important;
        align-items: center !important;
        justify-content: space-between !important;
        gap: 6px !important;
        background: var(--button-background) !important;
        border: none !important;
        height: 36px !important;
        outline: 0 !important;
        font-size: 14px !important;
        border-radius: 18px !important;
        cursor: pointer !important;
        transition: 0.15s !important;
        padding: 0 16px !important;
        box-sizing: border-box !important;
        color: var(--summarize-button-selected-icon-color) !important;
        font-family: "Roboto", "Arial", sans-serif !important;
        font-weight: 500 !important;
        line-height: 36px !important;
      }

